#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
#define Clear(a) memset(a,0,sizeof(a))
using namespace std;
const int N=2e5+10,M=1e7+10;
bool f1;
int ch[M][26],idx[M],tot,cdt;char s[M],t[M];int n,m;
inline void rd(string &s)
{
	char ch=getchar();while(ch<'a'||ch>'z')ch=getchar();
	s.clear();while(ch<='z'&&ch>='a')s+=ch,ch=getchar();
}
struct ACAM
{
	struct Node
	{
		int ch[27],tot,nxt;bool vis;
		Node(){memset(ch,0,sizeof(ch));tot=nxt=0;vis=false;}
	};
	vector<Node> a;queue<int> q;
	inline void Init(){a.assign(1,Node());return;}
	ACAM(){a.assign(1,Node());return;}
	inline int newNode()
	{
		int tmp=a.size();
		a.push_back(Node());
		return tmp;
	}
	inline void ins(string &s)
	{
//		cout<<"ins :: "<<s<<endl;
		int p=0,len=s.size();
		rep(0,len-1,i)
		{
			int x=a[p].ch[s[i]-'a'];
			if(!x)x=newNode(),a[p].ch[s[i]-'a']=x;p=x;
		}
		a[p].tot++;

	}
	inline void build()
	{
		while(!q.empty())q.pop();
		rep(0,26,i)if(a[0].ch[i])
		{
			q.push(a[0].ch[i]);
			a[a[0].ch[i]].nxt=0;
		}
		while(!q.empty())
		{
			int u=q.front();q.pop();
			rep(0,26,i)
			{
				if(a[u].ch[i])
				{
					q.push(a[u].ch[i]);
					a[a[u].ch[i]].nxt=a[a[u].nxt].ch[i];
				}
				else
				{
					a[u].ch[i]=a[a[u].nxt].ch[i];
				}
			}
		}
	}
	inline int qry(string &s)
	{
//		cout<<"qry :: "<<s<<endl;
		int len=s.size(),p=0,ans=0;
//		stack<int> stk;
		rep(0,len-1,i)
		{
			p=a[p].ch[s[i]-'a'];
			for(int j=p;j;j=a[j].nxt)
			{
				ans+=a[j].tot;
//				a[j].vis=true;
//				stk.push(j);
			}
		}
//		while(!stk.empty())a[stk.top()].vis=false,stk.pop();
		return ans;
	}
}a[N];
bool f2;
inline int Qry(string &s)
{
	int n=s.size(),p=0;
	rep(0,n-1,i)
	{
		int &x=ch[p][s[i]-'a'];
		if(!x)x=++cdt;p=x;
	}
	if(!idx[p])idx[p]=++tot;
	return idx[p];
}
int main()
{
//	printf("Mem :: %.6lf MB\n",1.*(&f1-&f2)/1024/1024);
//	FIN("P14363_11.in");
//	FOUT("QWQ.out");
	scanf("%d%d",&n,&m);
	rep(1,n,i)
	{
		string s1,s2;rd(s1);rd(s2);
		if(s1==s2)continue;
		int ql=0,qr=s1.size()-1;
		while(s1[ql]==s2[ql])++ql;
		while(s1[qr]==s2[qr])--qr;
		string B;
		rep(ql,qr,i)B+=s1[i],B+=s2[i];
		string A;
		rep(0,ql-1,i)A+=s1[i];
		A+='{';
		rep(qr+1,int(s1.size())-1,i)A+=s1[i];
		a[Qry(B)].ins(A);
//		cout<<i<<" :: "<<A<<" "<<B<<" "<<Qry(B)<<endl;
	}
	rep(1,tot,i)a[i].build();
	rep(1,m,i)
	{
		string s1,s2;rd(s1);rd(s2);
		if(s1.size()!=s2.size()){puts("0");continue;}
		int ql=0,qr=s1.size()-1;
		while(s1[ql]==s2[ql])++ql;
		while(s1[qr]==s2[qr])--qr;
		string B;
		rep(ql,qr,i)B+=s1[i],B+=s2[i];
		string A;
		rep(0,ql-1,i)A+=s1[i];
		A+='{';
		rep(qr+1,int(s1.size())-1,i)A+=s1[i];
		int ans=a[Qry(B)].qry(A);
//		if(i%10000==0)
		printf("%d\n",ans);
//		cout<<i<<" :: "<<A<<" "<<B<<endl;
	}
//	string gg="bdce",qq="xa{x";
//	cout<<"cnm :: "<<Qry(gg)<<' '<<a[Qry(gg)].qry(qq)<<endl;
}
